import sys
def add(a: int , b :int) -> float:   # type hint added here so that it'll be clear what the input types are in addition to return value being a floating point number (default is integer). Also, Python requires colon(:), space and indentation for function definition.
    """Add two numbers"""  # Docstring explaining purpose of this method if needed by others reading your code or even yourself when you first write it down on paper/write in team sessions etc..   This line should be the same length as above one, otherwise Python will throw an error while parsing and can't understand what is written here.
    return a + b  # Correct indentation for function definition according to PEP8 standards (Python style guide) with correct type hinting added in addition of docstring explaining the purpose if needed by others reading your code or even yourself when you first write it down on paper/write in team sessions etc..
    
def subtract(a: int , b :int)-> float:#type hints for input types and return value. Correct indentation according to PEP8 standards with correct docstring explaining the purpose if needed by others reading your code or even yourself when you first write it down on paper/write in team sessions etc..
    """Subtract one number from another"""  # Docstrings should be as same length and formatting is also consistent. This line will have to match with above docstring exactly for the Python interpreter not to throw any error while parsing code or understand it correctly by others reading your work on paper/write in team sessions etc..
    return a - b  # Correct indentation according PEP8 standards and also correct type hinting.   This line should be same length as above one, otherwise Python will not know how to interpret this part of the code which can lead into errors while running your script or understanding other's work on paper/write in team sessions etc..
    
def multiply(a: int , b :int) -> float:#type hints for input types and return value. Correct indentation according to PEP8 standards with correct docstring explaining the purpose if needed by others reading your code or even yourself when you first write it down on paper/write in team sessions etc..
    """Multiply two numbers"""  # Docstrings should be as same length and formatting is also consistent. This line will have to match exactly for Python interpreter not to throw any error while parsing the script, understanding other's work or reading your code on paper/write in team sessions etc..
    return a * b   # Correct indentation according PEP8 standards and correct type hinting here. This line should be same length as above one otherwise Python will not understand this part of it correctly which can lead into errors while running the script or understanding other's work on paper/write in team sessions etc..
    
# read input from stdin  #readline is used to get a single string at once, split() splits by space and map(int) converts all items of list_input which are strings into integers. Then we use sum function with generator expression for getting the total Summation while using round method in addition calculating mean
list_input = sys.stdin.readlines()  # read lines from std input, return a string and then split by newline character '\n' to get list of numbers as strings which are converted into integers on map function call with int(). Then sum up all the elements using generator expression for getting total Summation
total_sum = sum(map(int ,list_input))   # convert each item in input string (after splitting by newline character) and then to integer.  This gives us a list of integers, we can use it directly with addition operator '+' which will give the TotalSummations from all numbers
mean = total_sum / len(list_input )   # calculate mean using summation divided by length (number count), this is also typecasted to float.  This gives us a floating point number, we can use it directly with addition operator '+' and rounding off as required in problem statement
# print results here you should have the exact same indentation for printing statements too because Python will not understand them otherwise which could lead into errors while running your script or understanding other’s work on paper/write team sessions etc..  This line is also correct.   # Printing Statements are formatted in PEP8 standards and consistent with above one, this should be same length as the previous print statement
print("Sum:", total_sum)    # Correct indentation for printing statements too because Python will not understand them otherwise which could lead into errors while running your script or understanding other’s work on paper/write team sessions etc..  This line is also correct.   Printing Statements are formatted in PEP8 standards and consistent with above one, this should be same length as the previous print statement
